import React, { useState, useRef, useEffect  } from "react";
import { Link, useNavigate } from "react-router-dom";
import { Image, Form} from 'react-bootstrap'
import BASE_URL from "../config";

function Logout() {
    const [t, setT] = useState({});
  const [language, setLanguage] = useState("en");

  const [captchaText, setCaptchaText] = useState("");
  const [captchaImage, setCaptchaImage] = useState("");
  const [loginSalt, setLoginSalt] = useState("");
  const [failedAttempts, setFailedAttempts] = useState(0);
  const [showCaptcha, setShowCaptcha] = useState(false);

  const [user, setUser] = useState({
    username: "",
    password: ""
  });

  const navigate = useNavigate();
  
  useEffect(() => {
    const lang = localStorage.getItem("language") || "en";
    setLanguage(lang);

    fetch(`${BASE_URL}/api/translations?lang=${lang}`)
      .then(res => res.json())
      .then(data => {
        setT(data);
      });


    const cssFiles = [
      "assets/login/vendors/bootstrap/css/bootstrap.min.css",
      "assets/fonts/font-awesome-4.7.0/css/font-awesome.min.css",
      "assets/login/vendors/animate/animate.css",
      "assets/login/vendors/css-hamburgers/hamburgers.min.css",
      "assets/login/vendors/select2/select2.min.css",
      "assets/login/css/util.css",
      "assets/login/css/main.css",
    ];

    const links = cssFiles.map((href) => {
      const link = document.createElement("link");
      link.rel = "stylesheet";
      link.href = href;
      document.head.appendChild(link);
      return link;
    });

  const loadedScripts = [];

  const loadScript = (src) =>
    new Promise((resolve, reject) => {
      const existing = document.querySelector(`script[src="${src}"]`);

      if (existing) {
        resolve();
        return;
      }

      const script = document.createElement("script");
      script.src = src;
      script.async = false;

      script.onload = () => resolve();
      script.onerror = () => reject(new Error(`Failed to load ${src}`));

      document.body.appendChild(script);
      loadedScripts.push(script);
    });

  const loadAll = async () => {
    try {
      await loadScript("/assets/login/vendors/jquery/jquery-3.2.1.min.js");
      await loadScript("/assets/login/vendors/bootstrap/js/popper.js");
      await loadScript("/assets/login/vendors/bootstrap/js/bootstrap.min.js");
      await loadScript("/assets/login/vendors/select2/select2.min.js");
      await loadScript("/assets/login/vendors/tilt/tilt.jquery.min.js");
      await loadScript("/assets/login/js/main.js");

      if (window.$ && window.$.fn.tilt) {
        window.$(".js-tilt").tilt({
          scale: 1.1,
        });
      }
    } catch (err) {
      console.error("Script loading failed:", err);
    }
  };

  loadAll();

  const loadCaptcha = () => {
    setCaptchaImage(
      `${BASE_URL}/auth/captcha?${Date.now()}`
    );
  };

  loadCaptcha();

  fetch(`${BASE_URL}/auth/login-salt`, {
    method: "GET",
    credentials: "include",
  })
    .then((res) => res.json())
    .then((data) => {
      setLoginSalt(data.salt);
    })
    .catch((err) => {
      console.error(err);
    });

  // Cleanup when leaving Login page
  return () => {

    links.forEach((link) => {
        if (document.head.contains(link)) {
          document.head.removeChild(link);
        }
      });
      
    loadedScripts.forEach((script) => {
      if (script.parentNode) {
        script.parentNode.removeChild(script);
      }
    });

    if (window.$) {
      window.$(".js-tilt").tilt?.destroy?.call(
        window.$(".js-tilt")
      );
    }
  };
}, []);

  // helper function for sha256
  const sha256 = async (message) => {
      const msgBuffer = new TextEncoder().encode(message);

      const hashBuffer = await crypto.subtle.digest("SHA-256", msgBuffer);

      const hashArray = Array.from(new Uint8Array(hashBuffer));

      return hashArray
        .map((b) => b.toString(16).padStart(2, "0"))
        .join("");
  };

  // handle input change
  const handleChange = (e) => {
    setUser({
      ...user,
      [e.target.name]: e.target.value
    });
  };

  // login api
  const handleLogin = async (e) => {
    e.preventDefault();

    try {

      if (showCaptcha && !captchaText) {
          alert("Please enter captcha");
      return;
    }
      // Step 1: Convert password to SHA256
      const passwordHash = await sha256(user.password);

      // Step 2: Create request hash using session salt
      const finalHash = await sha256( passwordHash + loginSalt);

      // Step 3: Change textbox value
      setUser((prev) => ({
        ...prev,
        password: finalHash
      }));

      // Step 4: API Call
      const res = await fetch(
      `${BASE_URL}/user/login`,
        {
          method: "POST",
          credentials: "include",
          headers: {
            "Content-Type": "application/json"
          },
          body: JSON.stringify({
            username: user.username,
            password: passwordHash,
            finalHash: finalHash,
            captcha: showCaptcha ? captchaText : ""
          })
        }
      );

      const data = await res.json();

      if (data.success) {
        setFailedAttempts(0);
        setShowCaptcha(false);
        setCaptchaText("");

        localStorage.setItem("isLoggedIn", "true");
        localStorage.setItem("user", JSON.stringify(data));
        console.log(data);

        navigate("/dashboard");
      } 
      else {
        const attempts = failedAttempts + 1;
        setFailedAttempts(attempts);
          if (attempts >= 2) {
              setShowCaptcha(true);
              setCaptchaImage(`${BASE_URL}/auth/captcha?${Date.now()}`);
              setCaptchaText("");
          }
        alert(data.message || "Invalid credentials");
    } 
  }
  catch (err) {
          console.error(err);
          setCaptchaImage(`${BASE_URL}/auth/captcha?${Date.now()}`);
          alert("Server error");
          setCaptchaText("");
    }
  };
  const loadtranslations = async (e) => {
    const lang = e.target.value;
            setLanguage(lang);
            localStorage.setItem("language", lang);

            fetch(`${BASE_URL}/api/translations?lang=${lang}`)
              .then(res => res.json())
              .then(data => setT(data));
  };
  
  return (
    <div className="limiter">
		<div className="container-login100">
			<div className="wrap-login100">
				<div className="login100-pic js-tilt" data-tilt>
					<span className="login100-form-title">
						<h2 class="mb-0 mt-4 text-white">User Logout successfully.</h2>
					</span>
					<Image src="/assets/images/logo.png" alt="IMG" fluid  />
					<div className="text-center p-t-5">
						"Uttarakhand Renewable Energy Development Agency (UREDA)"
                         <Link to="/" className="btn bg-white text-primary d-inline-flex align-items-center">  Back to Login</Link>
					</div>
				</div>
        				
			</div>
		</div>
	</div>
  
  );
}

export default Logout;
